func_start = content.find("void emitBinary", start_idx)
func_end = content.find("/*\n  ----------------------------------------------------------------\n  TASK 5 END", start_idx)
if func_end < 0:
    func_end = content.rfind("}", start_idx, end_idx)
    if func_end > 0:
        func_end = content.find("\n", func_end) + 1

# Print what we found
print(f"Found TASK 5 region: {start_idx} - {end_idx}")
print(f"emitBinary at: {func_start}")
content_before = content[:func_start]
content_after = content[end_idx:]

# Write replacement
new_code = '''
  //=== TASK 5: Student Implementation ====================================
  void emitBinary(const llvm::BinaryOperator& bo)
  {
    llvm::Register dst = vregOf(&bo);
    llvm::Register lhs = emitLoadValue(bo.getOperand(0));
    llvm::Register rhs = emitLoadValue(bo.getOperand(1));

    switch (bo.getOpcode()) {
      case llvm::Instruction::Add:  emitVAdd(dst, lhs, rhs); return;
      case llvm::Instruction::Sub:  emitVSub(dst, lhs, rhs); return;
      case llvm::Instruction::Mul:  emitVMul(dst, lhs, rhs); return;
      case llvm::Instruction::SDiv: emitVDiv(dst, lhs, rhs); return;
      case llvm::Instruction::UDiv: emitMC(llvm::RISCV::DIVU, {mcReg(dst), mcReg(lhs), mcReg(rhs)}); return);
      case llvm::Instruction::SRem: emitVRem(dst, lhs, rhs); return;
      case llvm::Instruction::URem: emitMC(llvm::RISCV::REMU, {mcReg(dst), mcReg(lhs), mcReg(rhs)}); return;
      case llvm::Instruction::And:  emitVAnd(dst, lhs, rhs); return;
      case llvm::Instruction::Or:   emitVOr(dst, lhs, rhs); return;
      case llvm::Instruction::Xor:  emitVXor(dst, lhs, rhs); return;
      case llvm::Instruction::Shl:
        if (auto* ci = dyn_cast<llvm::ConstantInt>(bo.getOperand(1)))
          emitVSlli(dst, lhs, ci->getZExtValue());
        else
          emitVSll(dst, lhs, rhs);
        return;
      case llvm::Instruction::LShr:
        if (auto* ci = dyn_cast<llvm::ConstantInt>(bo.getOperand(1)))
          emitVSrli(dst, lhs, ci->getZExtValue());
        else
          emitVSrl(dst, lhs, rhs);
        return;
      case llvm::Instruction::AShr:
        if ( ci = dyn_castConstantInt>(bo.getOperand(1)))
          emitVSrai(dst, lhs, ci->getZExtValue());
        else
          emitVSra(dst, lhs, rhs);
        return;
      default:
        llvm::report_fatal_error("unsupported binary opcode");
    }
  }

  void emitICmpInst(const llvmInst(const llvm::ICmpInst& ci)
  {
    llvm::Register dst = vregOf(&ci);
    llvm::Register lhs = emitLoadValue(ci.getOperand(0));
    llvm::Register rhs = emitLoadValue(ci.getOperand(1));
    llvm::Register tmp = nextTempVReg();
    llvm::Register one = nextTempVReg();

    switch (ci.getPredicate()) {
      case llvm::CmpInst::ICMP_EQ:
        emitVXor(tmp, lhs, rhs);
        emitVSltiu(dst, tmp, 1);
        return;
      case llvm::CmpInst::ICMP_NE:
        emitVXor(tmp, lhs, rhs);
        emitVSltiu(tmp, tmp, 1);
        emitVXori(dst, tmp, 1);
        return;
      case llvm::CmpInst::ICMP_SLT:
        emitVSlt(dst, lhs, rhs);
        return;
      case llvm::CmpInst::ICMP_SLE:
        emitVSlt(tmp, rhs, lhs);
        emitVXori(dst, tmp, 1);
        ret;
      case llvm::CmpInst::ICMP_SGT:
        emitVSlt(dst, rhs, lhs);
        return;
      case llvm::CmpInst::ICMP_SGE:
        emitVSlt(tmp, lhs, rhs);
        emitVXori(dst, tmp, 1);
        return;
      case llvm::CmpInst::ICMP_ULT:
        emitVSltu(dst, lhs, rhs);
        return;
      case llvm::CmpInst::ICMP_ULE:
        emitVSltu(tmp, rhs, lhs);
        emitVXori(dst, tmp, 1);
        return;
      case llvm::CmpInst::ICMP_UGT:
        emitVSltu(dst, rhs, lhs);
        return;
      case llvm::CmpInst::ICMP_UGE:
        emitVSltu(tmp, lhs, rhs);
        emitVXori(dst, tmp, 1);
        return;
      default:
        llvm::report_fatal_error("unsupported icmp predicate");
    }
  }

  void emitLoadInst(const llvm::LoadInst& li)
  {
    llvm::Register dst = vregOf(&li);
    llvm::Register addr = emitLoadValue(li.getPointerOperand());

    if (dl_.getTypeStoreSize(li.getType()) == 4)
      emitVLoad32(dst, addr);
    else
      emitVLoad(dst, addr);
  }

  void emitStoreInst(const llvm::StoreInst& si)
  {
    llvm::Register val = emitLoadValue(si.getValueOperand());
    llvm::Register addr = emitLoadValue(si.getPointerOperand());

    if (dl_.getTypeStoreSize(si.getValueOperand()->getType()) == 4)
      emitVStore32(val, addr);
    else
      emitVStore(val, addr);
  }
'''

